{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household income at or below 200% of the federal poverty guidelines. 2025 limits: 1: $31,300; 2: $42,300; 3: $53,300; 4: $64,300; 5: $75,300; 6: $86,300; 7: $97,300; 8: $108,300. Add $11,000 per additional member beyond 8.[2][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Priority to households with members over age 60, disabilities, children, or high energy burden/usage.[1][2][5]", "Automatic income eligibility if received SSI, TANF, or HEAP (not Emergency HEAP) in last 12 months.[1][2][5]", "Application required even for automatic eligibility.[2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free weatherization services based on home inspection and energy audit: attic/wall/floor/basement insulation; blower-door air leakage reduction; duct sealing; heating system/water heater repairs/replacements; venting exhaust equipment; health/safety inspections/testing; emergency repairs; client education. Services at no cost for single-family homes; multi-family may require arrangements.[1][3][4][5][6][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local agency by county via https://coadinc.org/energy-services/hwap/ (Ohio HWAP Service Providers and Contacts by County link).[1]", "State helpline: (800) 848-1300.[3][6]", "Example providers: COAD (740) 594-8499 for specific counties; IMPACT (614-252-2799 prompt #4 then 1, or https://www.impactca.org/hwap-intake-form, weatherization@impactca.org for Franklin County zips); NOCAC (419-784-5393, kfeeney@nocac.org); MORPC (614-621-1171 for Franklin County).[1][4][6][7]", "In-person/mail via local agencies."],
    "processing_time": "Not specified in sources.",
    "waitlist": "Served in order of application receipt per priority ranking; waitlists likely due to funding limits but not detailed.[6]",
    "forms": ["Interest/application forms via local providers (e.g., IMPACT HWAP Intake Form); no statewide form number specified."],
    "documents": ["Proof of income (90 days or total annual household); ID; Social Security card/number; recent electric/gas bill; for renters: landlord/property manager contact info.[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via local agencies in each county; some providers serve specific zips/counties (e.g., IMPACT Franklin County zips, COAD specific counties).[1][4]",
    "regional_variations": "Administered by different local agencies per county with varying contacts, intake processes, and potentially wait times; services consistent but access points differ.[1][2][4][6][7]",
    "offices_or_providers": ["See county provider list at provider link in [1]; examples: COAD, IMPACT, NOCAC, MORPC, BridgesCAP."]
  },
  "official_source": "https://development.ohio.gov/individual/energy-assistance/6-home-weatherization-assistance-program",
  "gotchas": ["Must contact county-specific local agency, not a single statewide office; priority groups served first, others wait by application order; renters eligible but need landlord info; recent SSI/TANF/HEAP recipients auto-eligible but still apply; no services if received HWAP in last 12 months implied by priority rules; multi-family units may not be fully free.[1][2][4][6]"],
  "data_shape_notes": "County-administered with local providers and contacts; priority-based service order; income table scales by household size; 200% FPG fixed limit."
}

{
  "name": "Ohio Senior Health Insurance Information Program (OSHIIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all Medicare beneficiaries, including seniors and people under age 65 with disabilities[3][4]",
    "asset_limits": "No asset limits or tests apply[3]",
    "other_requirements": ["Must be enrolled in or eligible for Medicare[3][4]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, objective one-on-one counseling; health insurance information; education on Medicare, Part D, Medicare Advantage, Medicare supplement insurance, long-term care insurance, financial assistance programs for limited income, cost-saving programs; explanation of benefits; enrollment assistance; claims help; public events and speaker's bureau[1][2][3]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-686-1578 (hotline, Mon-Fri 7:30am-5pm)[3][4][6]", "Email: oshiipmail@insurance.ohio.gov[6]", "Website: https://insurance.ohio.gov/consumers/medicare/01-oshiip[3][4]", "Local coordinators via hotline or list at https://insurance.ohio.gov/consumers/medicare/oshiip-coordinators-list[9]", "In-person: Through trained volunteers and local providers (e.g., Area Office on Aging sites)[1][2]"],
    "processing_time": "No formal application or processing; services provided immediately upon contact[3]",
    "waitlist": null,
    "forms": ["No specific forms required; counseling and assistance provided directly[3]"],
    "documents": ["Medicare card or details recommended for personalized counseling, but not mandatory[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; serves all Ohio Medicare beneficiaries[4]",
    "regional_variations": "Delivered through local coordinators, volunteers, and providers in various counties (e.g., Buckeye Hills region: Athens, Hocking, etc.; Northwest Ohio: Erie, Lucas, etc.), but core services uniform statewide[1][2][9]",
    "offices_or_providers": ["Central office: 50 W Town St, 3rd Floor Suite 300, Columbus OH 43215[4][5]", "Local coordinators listed at https://insurance.ohio.gov/consumers/medicare/oshiip-coordinators-list[9]"]
  },
  "official_source": "https://insurance.ohio.gov/consumers/medicare/01-oshiip[3]",
  "gotchas": ["Not a benefits-paying program—provides information and counseling only, no direct financial aid or healthcare services; must be Medicare-eligible (people miss that it includes under-65 disabled); contact local coordinators if hotline busy; funded by federal/state grants, completely free and unbiased[3][4]", "Does not handle SSA applications directly (refer to other numbers like 800-633-4227 for Medicare enrollment)[1]"],
  "data_shape_notes": "no income/asset test; counseling/education only for Medicare beneficiaries; statewide with local delivery coordinators; immediate service, no waitlist or application"
}

{
  "name": "Home-Delivered Meals (via Ohio Aging Network)",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits statewide; services offered on sliding fee scale with possible co-pay based on monthly income in some counties like Franklin. Exact dollar amounts not specified in sources[1].",
    "asset_limits": "No asset limits mentioned or applicable[1][5][6].",
    "other_requirements": ["Must be a resident of the service area/county", "Homebound or unable to prepare own meals due to age, disability, or health condition", "Need for nutrition to support independence (functional impairment implied via Ohio Administrative Code OAC 173-39-02.14)[2]", "Person-Centered Service Plan required for Medicaid waivers like PASSPORT[2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Nutritionally balanced meals (1/3 of daily needs) delivered to home, up to 2 meals per day; options include hot daily meals, weekly frozen meals, kosher, vegetarian, diabetic, renal; delivered 5 days/week (Mon-Fri, e.g., 10:30am-1pm); includes friendly volunteer visit for socialization[1][2][5][6].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) or provider: e.g., Franklin County call (614) 525-6200 weekdays 9AM-4:30PM ET or enroll online via county site[1]", "Northeast Ohio: referrals@vantageaging.org or 330-832-7220[6]", "Statewide Ohio Department of Aging: 1-800-266-4346[2]", "Geauga County: Contact Department on Aging (specific phone not listed, inquire via site)[5]", "For PASSPORT/Medicaid waivers: Through ODA Aging Network or Ohio Medicaid providers[3]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Possible regional waitlists implied but not detailed; varies by local provider capacity",
    "forms": ["Person-Centered Service Plan (required for delivery parameters)[2]", "Diet order from licensed prescriber for therapeutic meals like diabetic[6]"],
    "documents": ["Proof of age/residency", "Income info for sliding fee/co-pay determination", "Diet order for special diets", "Medicaid/PASSPORT enrollment if applicable[3][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered via local Ohio Aging Network (33 Area Agencies on Aging covering all counties); must contact local AAA/provider",
    "regional_variations": "Varies by county/provider: e.g., Franklin sliding fee/co-pay[1]; Geauga no fees (donations appreciated), 5 days/week[5]; Northeast Ohio (Vantage) accepts Title III-C, PASSPORT, private pay, multiple funders[6]; meal types/options differ (e.g., diabetic meals from 2025 in NE Ohio)[6]",
    "offices_or_providers": ["Franklin County Senior Options: (614) 525-6200[1]", "Geauga County Department on Aging[5]", "Vantage Aging (NE Ohio): 330-832-7220[6]", "Ohio Department of Aging: 1-800-266-4346, Aging.Ohio.gov[2]"]
  },
  "official_source": "https://aging.ohio.gov/ and local AAA sites; OAC 173-39-02.14, OAC 5160-44-11[2]",
  "gotchas": ["Not entirely free—sliding fee/co-pay in some areas based on income[1]", "Must contact LOCAL county AAA/provider, not centralized statewide application[1][5][6]", "Requires functional need/homebound status, not just age 60+[2]", "Therapeutic diets need prescriber order[6]", "Medicaid waivers (e.g., PASSPORT) have separate enrollment[3]", "Donations often requested even if free[5][7]"],
  "data_shape_notes": "Decentralized via 33 local Area Agencies on Aging; no uniform statewide income table or processing time; eligibility/fees vary by county/provider; tied to OAA Title III and Medicaid waivers like PASSPORT"
}

{
  "name": "Ohio Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resident of Ohio receiving long-term care services in nursing homes, assisted living, group homes, home care, or programs like MyCare Ohio."[1][9]]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for rights, investigation and resolution of complaints about quality of care and life (e.g., unappetizing food, inadequate hygiene, abuse, neglect, billing, admission/discharge issues), assistance with care planning, Medicare/Medicaid questions; provided by certified staff and volunteers; no fixed dollar amounts or hours.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-282-1206 (statewide hotline).","Local regional office (12 offices covering 88 counties).","Website: https://aging.ohio.gov/ombudsman for local contacts."[9][8]],
    "processing_time": "Immediate response to complaints; no formal processing timeline specified.",
    "waitlist": null,
    "forms": ["No specific application forms; contact to file complaint or request assistance."],
    "documents": ["None required; provide details of concern or complaint verbally or in writing."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all 88 counties.",
    "regional_variations": "Delivered through 12 regional programs with local offices and providers (e.g., ABLE serves 17 northwest counties including Allen, Auglaize, etc.; Direction Home of Eastern Ohio serves Ashtabula, Columbiana, etc.); variations in local staff/volunteers but uniform services statewide.",
    "offices_or_providers": ["12 regional long-term care ombudsman programs; find local via https://aging.ohio.gov/ombudsman or 800-282-1206."]
  },
  "official_source": "https://aging.ohio.gov/ombudsman",
  "gotchas": ["Not a service provider or entitlement program—purely advocacy and complaint resolution, not direct care or financial aid.","Free and confidential, but requires contacting for specific issues; no proactive eligibility screening.","People confuse with PASSPORT (in-home services for low-income); Ombudsman is separate.[3]","Services for residents in long-term care settings only, including home-based."],
  "data_shape_notes": "no income test; advocacy-only (no financial benefits or service hours); delivered via 12 regional programs covering all counties; complaint-driven, not application-based enrollment."
}
